"""E2e tests for category: proxy."""

import os

import pytest
from kreuzcrawl import scrape, create_engine, CrawlConfig, ProxyConfig


@pytest.mark.asyncio
async def test_proxy_authenticated() -> None:
    """Proxy with username and password credentials authenticates successfully."""
    engine_config = CrawlConfig(
        proxy=ProxyConfig(
            password="proxypass", url="http://127.0.0.1:8889", username="proxyuser"
        ),
        respect_robots_txt=False,
    )
